// HMAC-SHA256 verify the ElevenLabs-Signature header, then append to NDJSON sink.
// Mirrors src/security/elevenlabs-signature.ts in the repo.
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const SECRET = $env.N8N_WEBHOOK_SECRET || $env.ELEVENLABS_WEBHOOK_SECRET || '';
const TOLERANCE_SEC = 30 * 60;

const item = $input.first();
const headers = item.json.headers || {};
const sigHeader = headers['elevenlabs-signature'] || headers['ElevenLabs-Signature'] || '';
const rawBody = item.json.rawBody || JSON.stringify(item.json.body || item.json);

const parseSig = (h) => {
  const parts = h.split(',').reduce((acc, p) => { const [k, v] = p.split('='); acc[k] = v; return acc; }, {});
  return {t: parts.t ? parseInt(parts.t, 10) : NaN, v0: parts.v0 || ''};
};
const {t, v0} = parseSig(sigHeader);
if (!t || !v0) return [{json: {ok: false, reason: 'malformed_header'}}];
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - t) > TOLERANCE_SEC) return [{json: {ok: false, reason: 'stale'}}];
const expected = crypto.createHmac('sha256', SECRET).update(`${t}.${rawBody}`).digest('hex');
if (expected.length !== v0.length || !crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(v0))) {
  return [{json: {ok: false, reason: 'signature_mismatch'}}];
}

const payload = typeof item.json.body === 'string' ? JSON.parse(item.json.body) : (item.json.body || item.json);
const type = payload.type || 'unknown';

// Append to NDJSON sink (one file per type per day)
const today = new Date().toISOString().slice(0, 10);
const dir = path.join(process.cwd(), 'logs', 'elevenlabs', 'post-call');
fs.mkdirSync(dir, {recursive: true});
const file = path.join(dir, `${type}-${today}.ndjson`);
fs.appendFileSync(file, JSON.stringify(payload) + '\n');

return [{json: {ok: true, type, conversation_id: payload.data?.conversation_id, sink: file}}];
